rmalized(EzSkinJsonDocument.Parse(json));        }        public bool CreateInitial(Ez2ConfigManager config)        {            if (!IsSupported || HasFile)                return false;            var live = skinManager.CurrentSkinInfo.Value;            if (!EzSkinJsonSupport.IsSupported(live))                return false;            if (live.ID != SkinId)                throw new InvalidOperationException("Cannot create EzSkin.json for a skin that is no longer current.");            if (!live.IsManaged)                throw new InvalidOperationException("Cannot create EzSkin.json because the current skin is not writable.");            string json = EzSkinJsonBridge.CreateNormalizedSnapshot(config);            live.PerformWrite(skin => writeSkinJsonText(skin, json));            skinManager.CurrentSkinInfo.TriggerChange();            HasFile = true;            savedSnapshot = json;            return true;        }        public bool Commit(Ez2ConfigManager config)        {            if (!IsSupported || !HasFile || !IsDirty(config))                return false;            var live = skinManager.CurrentSkinInfo.Value;            if (!EzSkinJsonSupport.IsSupported(live))                return false;            if (live.ID != SkinId)                throw new InvalidOperationException("Cannot commit EzSkin.json for a skin that is no longer current.");            if (!live.IsManaged)                throw new InvalidOperationException("Cannot commit EzSkin.json because the current skin is not writable.");            string jsonToCommit = EzSkinJsonBridge.CreateNormalizedSnapshot(config);            string savedJsonForBackup = savedSnapshot;            live.PerformWrite(skin =>            {                LastBackupFilename = backupService.BackupCurrentSkinJson(skin, savedJsonForBackup);                writeSkinJsonText(skin, jsonToCommit);            });            skinManager.CurrentSkinInfo.TriggerChange();            savedSnapshot = jsonToCommit;            return true;        }        public bool Remove()        {            if (!IsSupported || !HasFile)                return false;            var live = skinManager.CurrentSkinInfo.Value;            if (!EzSkinJsonSupport.IsSupported(live))                return false;            if (live.ID != SkinId)                throw new InvalidOperationException("Cannot remove EzSkin.json for a skin that is no longer current.");            if (!live.IsManaged)                throw new InvalidOperationException("Cannot remove EzSkin.json because the current skin is not writable.");            live.PerformWrite(skin =>            {                var existingFile = skin.GetFile(EzSkinJsonDocument.FILENAME);                if (existingFile != null)                    skinManager.DeleteFile(skin, existingFile);            });            skinManager.CurrentSkinInfo.TriggerChange();            HasFile = false;            savedSnapshot = string.Empty;            return true;        }        public void ApplyImportedDocument(EzSkinJsonDocument document, Ez2ConfigManager config)        {            EzSkinJsonBridge.Apply(document, config);        }        private string? readSkinJsonText(SkinInfo skin) => EzSkinJsonStorage.TryReadJson(skinManager, skin);        private void writeSkinJsonText(SkinInfo skin, string json)        {            using var stream = new MemoryStream(Encoding.UTF8.GetBytes(json));            var existingFile = skin.GetFile(EzSkinJsonDocument.FILENAME);            if (existingFile != null)                skinManager.ReplaceFile(skin, existingFile, stream);            else                skinManager.AddFile(skin, stream, EzSkinJsonDocument.FILENAME);        }    }}